mapper.select:
SELECT hpn.id, hpn.title, hpn.picture, hpn.type, hpn.is_top, hpn.add_datetime, hpn.operation_datetime, hpn.status, hpn.operator, COALESCE(t.name, s.name, u.nickname, u.username) AS authorName, COALESCE(t.name, s.name, u.nickname, u.username) AS creatorName, COALESCE(t_op.name, s_op.name, u_op.nickname, u_op.username) AS operatorName FROM home_page_notice hpn LEFT JOIN sys_tbuser u ON hpn.creator = u.id LEFT JOIN teacher t ON u.id = t.user_id AND u.user_type IN (0, 2) LEFT JOIN student s ON u.id = s.user_id AND u.user_type = 1 LEFT JOIN sys_tbuser u_op ON hpn.operator = u_op.id LEFT JOIN teacher t_op ON u_op.id = t_op.user_id AND u_op.user_type IN (0, 2) LEFT JOIN student s_op ON u_op.id = s_op.user_id AND u_op.user_type = 1
AND hpn.status = 1
AND hpn.type = #{param.type}
ORDER BY hpn.is_top DESC, hpn.add_datetime DESC LIMIT #{param.listNumber}

SELECT hpn.id, hpn.title, hpn.picture, hpn.type, hpn.is_top, hpn.add_datetime, hpn.operation_datetime, hpn.status, hpn.operator, hpn.show_type, COALESCE(t.name, s.name, u.nickname, u.username) AS authorName, COALESCE(t.name, s.name, u.nickname, u.username) AS creatorName, COALESCE(t_op.name, s_op.name , u_op.nickname, u_op.username) AS operatorName FROM home_page_notice hpn LEFT JOIN sys_tbuser u ON hpn.creator = u.id LEFT JOIN teacher t ON u.id = t.user_id AND u.user_type IN (0, 2) LEFT JOIN student s ON u.id = s.user_id AND u.user_type = 1 LEFT JOIN sys_tbuser u_op ON hpn.operator = u_op.id LEFT JOIN teacher t_op ON u_op.id = t_op.user_id AND u_op.user_type IN (0, 2) LEFT JOIN student s_op ON u_op.id = s_op.user_id AND u_op.user_type = 1
AND hpn.type = #{param.type}
AND hpn.title LIKE CONCAT('%', #{param.title}, '%')
AND hpn.status = #{param.status}
AND (hpn.deadline IS NULL OR hpn.deadline > #{param.deadlineAfter})
AND hpn.show_type = #{param.showType}
ORDER BY hpn.is_top DESC, hpn.add_datetime DESC

SELECT hpn.id, hpn.title, hpn.picture, hpn.type, hpn.is_top, hpn.add_datetime, hpn.operation_datetime, hpn.status, hpn.operator, hpn.show_type, COALESCE(t.name, s.name, u.nickname, u.username) AS authorName, COALESCE(t.name, s.name, u.nickname, u.username) AS creatorName, COALESCE(t_op.name, s_op.name , u_op.nickname, u_op.username) AS operatorName FROM home_page_notice hpn LEFT JOIN sys_tbuser u ON hpn.creator = u.id LEFT JOIN teacher t ON u.id = t.user_id AND u.user_type IN (0, 2) LEFT JOIN student s ON u.id = s.user_id AND u.user_type = 1 LEFT JOIN sys_tbuser u_op ON hpn.operator = u_op.id LEFT JOIN teacher t_op ON u_op.id = t_op.user_id AND u_op.user_type IN (0, 2) LEFT JOIN student s_op ON u_op.id = s_op.user_id AND u_op.user_type = 1
AND hpn.type = #{param.type}
AND hpn.title LIKE CONCAT('%', #{param.title}, '%')
AND hpn.status = #{param.status}
AND (hpn.deadline IS NULL OR hpn.deadline > #{param.deadlineAfter})
AND hpn.show_type = #{param.showType}
AND hpn.creator = #{creatorId}
ORDER BY hpn.is_top DESC, hpn.add_datetime DESC
